"use strict";const e=require("../common/vendor.js"),r=require("../utils/request.js");exports.getUserInfo=function(){return r.get("/user/info")},exports.login=function(e,t){return r.post("/user/login",{phone:e,code:t})},exports.loginByPassword=function(e,t){return r.post("/user/login/password",{username:e,password:t})},exports.register=function(e){return r.post("/user/register",e)},exports.updatePassword=function(e){return r.put("/user/password",e)},exports.updateUserInfo=function(e){return r.put("/user/info",e)},exports.uploadAvatar=function(r){return e.index.uploadFile({url:"http://localhost:8080/api/v1/user/avatar",filePath:r,name:"file",header:{Authorization:`Bearer ${e.index.getStorageSync("token")}`}})};
